/**
 * Output Guardrail Inspector
 * =========================
 * 
 * Performs post-screening on responses generated by the primary AI.
 * Uses a double-check approach:
 *   1. Fast rule-based Regex checks (detecting PII, SSN, database passwords, keys).
 *   2. Deterministic LLM evaluation (checking for toxicity, brand safety).
 * If non-compliant, replaces output with a generic, safe compliance block response.
 */

import { Ollama } from "ollama";
import { REGEX_PATTERNS, FALLBACK_MESSAGES, buildOutputGuardrailPrompt } from "./policies.js";

const ollama = new Ollama({ host: "http://localhost:11434" });

// Terminal colors
const C_GUARD = "\x1b[35m"; // Magenta for Guardrail
const C_ALERT = "\x1b[31m"; // Red for security block
const C_RESET = "\x1b[0m";

export class OutputGuardrail {
  constructor() {}

  /**
   * Scans and validates the generated response.
   * Returns { compliant: boolean, summary: string, text: string }
   */
  async checkOutput(generatedText) {
    console.log(`\n${C_GUARD}[Output Guardrail] Scanning AI response...${C_RESET}`);
    
    // ─── Layer 1: Rule-Based Regex Checks ────────────────────────────────────
    let piiMatched = false;
    const triggeredRegexRules = [];

    if (generatedText.match(REGEX_PATTERNS.API_KEY)) {
      piiMatched = true;
      triggeredRegexRules.push("API_KEY_SECRET");
    }
    if (generatedText.match(REGEX_PATTERNS.SSN)) {
      piiMatched = true;
      triggeredRegexRules.push("SSN");
    }
    if (generatedText.match(REGEX_PATTERNS.PASSWORD_MATCH)) {
      piiMatched = true;
      triggeredRegexRules.push("DB_PASSWORD");
    }

    if (piiMatched) {
      console.log(`   ${C_ALERT}🚨 BLOCK: Output leak detected via Regex signature matching!${C_RESET}`);
      console.log(`     ↳ Matches found for: ${triggeredRegexRules.join(", ")}`);
      return {
        compliant: false,
        summary: "PII leak detected via fast regex scanning.",
        text: FALLBACK_MESSAGES.OUTPUT_BLOCKED,
        triggeredPolicies: ["POLICY_005_PII_LEAK"],
        method: "regex"
      };
    }

    // ─── Layer 2: LLM-Based Policy Verification ─────────────────────────────
    const systemPrompt = `Output ONLY valid JSON. Your response must match the exact JSON schema provided by the user. Do NOT write preamble, markdown fences, or postamble.`;
    const userPrompt = buildOutputGuardrailPrompt(generatedText);

    let response;
    let fallbackUsed = false;

    try {
      response = await ollama.chat({
        model: "llama3.2",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt }
        ],
        format: "json",
        options: {
          temperature: 0.0
        }
      });
    } catch (err) {
      fallbackUsed = true;
      // If offline, since Regex passed, we default to compliant (fail-safe fallback)
      response = {
        message: {
          content: JSON.stringify({
            compliance_status: "compliant",
            evaluation_summary: "Offline check passed (regex compliant).",
            triggered_policies: []
          })
        }
      };
    }

    let result;
    try {
      const rawContent = response.message.content.trim();
      const cleanContent = rawContent.replace(/```json/g, "").replace(/```/g, "").trim();
      result = JSON.parse(cleanContent);
    } catch (e) {
      console.log(`${C_ALERT}[Output Guardrail] ❌ JSON Parse error. Output fail-closed active!${C_RESET}`);
      return {
        compliant: false,
        summary: "Internal output guardrail parsing error.",
        text: FALLBACK_MESSAGES.OUTPUT_BLOCKED,
        triggeredPolicies: ["GUARDRAIL_ERROR"],
        method: "llm"
      };
    }

    const compliant = result.compliance_status === "compliant";

    if (compliant) {
      console.log(`   ${C_GUARD}✅ PASS: AI response deemed compliant. Displaying response...${C_RESET}`);
      return {
        compliant: true,
        summary: result.evaluation_summary,
        text: generatedText,
        triggeredPolicies: [],
        method: "llm",
        fallbackUsed
      };
    } else {
      console.log(`   ${C_ALERT}❌ BLOCK: AI response deemed NON-COMPLIANT!${C_RESET}`);
      console.log(`     ↳ Reason: ${result.evaluation_summary}`);
      console.log(`     ↳ Triggered Policies: ${result.triggered_policies.join(", ")}`);
      return {
        compliant: false,
        summary: result.evaluation_summary,
        text: FALLBACK_MESSAGES.OUTPUT_BLOCKED,
        triggeredPolicies: result.triggered_policies || [],
        method: "llm",
        fallbackUsed
      };
    }
  }
}
